"use server";

import { serverAction } from "rwsdk/worker";
import { requestInfo } from "rwsdk/worker";

export interface Todo {
  id: string;
  title: string;
  done: boolean;
  createdAt: number;
}

function getEnv(): { TODOS: KVNamespace } {
  const { ctx } = requestInfo;
  if (!ctx.env) {
    throw new Error("env not found in ctx - ensure env injection middleware is configured");
  }
  return ctx.env as { TODOS: KVNamespace };
}

export async function listTodos(): Promise<Todo[]> {
  const env = getEnv();
  const todos: Todo[] = [];
  const list = await env.TODOS.list({ prefix: "todo:" });
  for (const key of list.keys) {
    const value = await env.TODOS.get(key.name);
    if (value) {
      todos.push(JSON.parse(value) as Todo);
    }
  }
  todos.sort((a, b) => a.createdAt - b.createdAt);
  return todos;
}

export const addTodo = serverAction(async (formData: FormData) => {
  const env = getEnv();
  const title = (formData.get("title") as string)?.trim();
  if (!title) return;

  const id = crypto.randomUUID();
  const todo: Todo = {
    id,
    title,
    done: false,
    createdAt: Date.now(),
  };
  await env.TODOS.put(`todo:${id}`, JSON.stringify(todo));
});

export const toggleTodo = serverAction(async (formData: FormData) => {
  const env = getEnv();
  const id = formData.get("id") as string;
  const done = formData.get("done") === "on";
  if (!id) return;

  const raw = await env.TODOS.get(`todo:${id}`);
  if (!raw) return;
  const todo: Todo = JSON.parse(raw);
  todo.done = done;
  await env.TODOS.put(`todo:${id}`, JSON.stringify(todo));
});

export const deleteTodo = serverAction(async (formData: FormData) => {
  const env = getEnv();
  const id = formData.get("id") as string;
  if (!id) return;
  await env.TODOS.delete(`todo:${id}`);
});

"use client";

import type { Todo } from "@/app/actions/todos";
import { addTodo, toggleTodo, deleteTodo } from "@/app/actions/todos";

export function TodoPage({ todos }: { todos: Todo[] }) {
  const remaining = todos.filter((t) => !t.done).length;

  return (
    <div>
      <h1>Todos</h1>

      {/* Add todo form */}
      <form action={addTodo}>
        <input
          type="text"
          name="title"
          aria-label="New todo title"
          placeholder="What needs to be done?"
        />
        <button type="submit">Add</button>
      </form>

      {/* Todo list */}
      <ul>
        {todos.map((todo) => (
          <li key={todo.id} data-done={String(todo.done)}>
            {/* Toggle form */}
            <form action={toggleTodo} style={{ display: "inline" }}>
              <input type="hidden" name="id" value={todo.id} />
              <ToggleCheckbox todo={todo} />
            </form>

            {/* Todo title */}
            <span data-testid="todo-title">{todo.title}</span>

            {/* Delete form */}
            <form action={deleteTodo} style={{ display: "inline" }}>
              <input type="hidden" name="id" value={todo.id} />
              <button type="submit" aria-label={`Delete ${todo.title}`}>
                Delete
              </button>
            </form>
          </li>
        ))}
      </ul>

      {/* Remaining count */}
      <p>
        <span data-testid="remaining-count">{remaining}</span> item
        {remaining !== 1 ? "s" : ""} left
      </p>
    </div>
  );
}

/**
 * A small "use client" wrapper for the checkbox that submits the toggle form
 * on change, so the form submits immediately when the checkbox is toggled.
 */
function ToggleCheckbox({ todo }: { todo: Todo }) {
  return (
    <input
      type="checkbox"
      name="done"
      defaultChecked={todo.done}
      aria-label={`Toggle ${todo.title}`}
      onChange={(e) => {
        e.currentTarget.form?.requestSubmit();
      }}
    />
  );
}

