import { render, route } from "rwsdk/router";
import { defineApp as _defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";
import { apiTodosHandler } from "@/app/pages/api-todos";

export type AppContext = {
  env?: Env;
};

const app = _defineApp([
  setCommonHeaders(),
  // Inject env into ctx via globalThis bridge
  ({ ctx }) => {
    const env = (globalThis as Record<string, unknown>).__rwsdk_env as Env | undefined;
    if (env) {
      ctx.env = env;
    }
  },
  render(Document, [
    route("/", Home),
    route("/api/todos", {
      get: apiTodosHandler,
    }),
  ]),
]);

// Wrap the fetch handler to capture env and make it available to middleware/server actions
const originalFetch = app.fetch;
app.fetch = async (request, env, cf) => {
  (globalThis as Record<string, unknown>).__rwsdk_env = env;
  try {
    return await originalFetch(request, env, cf);
  } finally {
    delete (globalThis as Record<string, unknown>).__rwsdk_env;
  }
};

export default app;

