import puppeteer from "puppeteer-core";

async function main() {
  const browser = await puppeteer.launch({
    headless: true,
    executablePath: "/usr/bin/chromium-browser",
    args: ["--no-sandbox", "--disable-setuid-sandbox"],
  });

  try {
    const page = await browser.newPage();

    // Navigate to the todo app
    await page.goto("http://localhost:5173/", { waitUntil: "networkidle0" });

    // Check initial state
    const initialRemaining = await page.$eval(
      '[data-testid="remaining-count"]',
      (el) => el.textContent
    );
    console.log("Initial remaining:", initialRemaining);

    // Add a new todo
    await page.type('[aria-label="New todo title"]', "Test from Puppeteer");
    await page.click('button[type="submit"]');
    await page.waitForNavigation({ waitUntil: "networkidle0" });

    // Check the new todo appears
    const titles = await page.$$eval('[data-testid="todo-title"]', (els) =>
      els.map((el) => el.textContent)
    );
    console.log("Todos after add:", titles);

    const remainingAfterAdd = await page.$eval(
      '[data-testid="remaining-count"]',
      (el) => el.textContent
    );
    console.log("Remaining after add:", remainingAfterAdd);

    // Toggle the first todo (checkbox)
    const firstCheckbox = await page.$('input[type="checkbox"][name="done"]');
    if (firstCheckbox) {
      await firstCheckbox.click();
      await page.waitForNavigation({ waitUntil: "networkidle0" });

      const remainingAfterToggle = await page.$eval(
        '[data-testid="remaining-count"]',
        (el) => el.textContent
      );
      console.log("Remaining after toggle:", remainingAfterToggle);
    }

    // Delete a todo
    const deleteButton = await page.$('button[aria-label^="Delete"]');
    if (deleteButton) {
      const label = await deleteButton.evaluate((el) =>
        el.getAttribute("aria-label")
      );
      console.log("Deleting:", label);
      await deleteButton.click();
      await page.waitForNavigation({ waitUntil: "networkidle0" });

      const titlesAfterDelete = await page.$$eval(
        '[data-testid="todo-title"]',
        (els) => els.map((el) => el.textContent)
      );
      console.log("Todos after delete:", titlesAfterDelete);

      const remainingAfterDelete = await page.$eval(
        '[data-testid="remaining-count"]',
        (el) => el.textContent
      );
      console.log("Remaining after delete:", remainingAfterDelete);
    }

    // Test the API endpoint
    const apiResponse = await page.evaluate(() =>
      fetch("/api/todos").then((r) => r.json())
    );
    console.log("\nAPI response:", JSON.stringify(apiResponse, null, 2));

    console.log("\nAll tests passed!");
  } catch (err) {
    console.error("Test failed:", err);
    process.exit(1);
  } finally {
    await browser.close();
  }
}

main();

// Test form submission via the RSC action protocol
// We need to encode the form data the same way React's useFormStatus does

import http from "http";

function request(path, options = {}) {
  return new Promise((resolve, reject) => {
    const req = http.request(
      "http://localhost:5173" + path,
      {
        method: options.method || "GET",
        headers: options.headers || {},
      },
      (res) => {
        let data = "";
        res.on("data", (chunk) => (data += chunk));
        res.on("end", () =>
          resolve({ status: res.statusCode, headers: res.headers, body: data })
        );
      }
    );
    req.on("error", reject);
    if (options.body) req.write(options.body);
    req.end();
  });
}

async function main() {
  // The RSC action protocol uses a specific multipart format with React's
  // decodeReply. Let's try using the form action directly.

  // First, let's check what happens when we POST to the root with the action
  // The form has action="" and includes hidden inputs for the action ID

  // Let's try a simpler approach: use the rwsdk action URL format
  // The client-side code intercepts form submissions and sends them as RSC actions
  // We need to replicate this

  // Let's try the raw RSC action protocol
  const boundary = "----FormBoundary" + Math.random().toString(36).slice(2);
  const actionId = "/src/app/actions/todos.ts#addTodo";

  // Build multipart body
  const parts = [];
  parts.push(`--${boundary}`);
  parts.push(`Content-Disposition: form-data; name="$ACTION_ID_${actionId}"`);
  parts.push("");
  parts.push("");
  parts.push(`--${boundary}`);
  parts.push(`Content-Disposition: form-data; name="title"`);
  parts.push("");
  parts.push("Test from action");
  parts.push(`--${boundary}--`);

  const body = parts.join("\r\n");

  const resp = await request(
    `/?__rsc_action_id=${encodeURIComponent(actionId)}`,
    {
      method: "POST",
      headers: {
        "Content-Type": `multipart/form-data; boundary=${boundary}`,
        Origin: "http://localhost:5173",
        Accept: "text/x-component",
      },
      body,
    }
  );

  console.log("Status:", resp.status);
  console.log("Content-Type:", resp.headers["content-type"]);
  console.log("Body (first 500 chars):", resp.body.substring(0, 500));

  // Now check if the todo was added via the API
  const apiResp = await request("/api/todos");
  const apiJson = JSON.parse(apiResp.body);
  console.log("\nAPI todos count:", apiJson.todos.length);
  console.log(
    "Titles:",
    apiJson.todos.map((t) => t.title)
  );
}

main().catch(console.error);
